"""matplotlib.gridspec — grid layout specification stubs."""


class GridSpec:
    def __init__(self, nrows, ncols, figure=None, left=None, bottom=None,
                 right=None, top=None, wspace=None, hspace=None,
                 width_ratios=None, height_ratios=None):
        self.nrows = nrows
        self.ncols = ncols

    def __getitem__(self, key):
        return SubplotSpec(self, key)

    def update(self, **kwargs):
        pass

    def tight_layout(self, figure, renderer=None, pad=1.08, h_pad=None, w_pad=None, rect=None):
        pass


class GridSpecFromSubplotSpec(GridSpec):
    def __init__(self, nrows, ncols, subplot_spec, wspace=None, hspace=None,
                 width_ratios=None, height_ratios=None):
        super().__init__(nrows, ncols)
        self.subplot_spec = subplot_spec


class SubplotSpec:
    def __init__(self, gridspec, key):
        self._gridspec = gridspec
        self._key = key

    def get_gridspec(self):
        return self._gridspec

    def subgridspec(self, nrows, ncols, **kwargs):
        return GridSpecFromSubplotSpec(nrows, ncols, self, **kwargs)
